def get_salary_record(employee_id: int, requesting_user_id: int, db_conn):
    if employee_id != requesting_user_id:
        # Allow HR managers; deny everyone else
        cursor = db_conn.cursor()
        cursor.execute('SELECT is_hr_manager FROM employees WHERE id = %s', (requesting_user_id,))
        row = cursor.fetchone()
        if not row or not row['is_hr_manager']:
            raise PermissionError('Access denied to salary record')
    cursor = db_conn.cursor()
    cursor.execute('SELECT * FROM salary_records WHERE employee_id = %s', (employee_id,))
    return cursor.fetchone()

